            { type = "list_item", text = "Fixed an issue where Blight of Weakness and Tongues would not properly display on the Cooldown Manager.", level = 2 },
            { type = "list_item", text = "Destruction", level = 1 },
            { type = "list_item", text = "Removed several spells from the Cooldown Manager, as they are no longer present in-game.", level = 2 },
            { type = "h3", text = "Décor Duel" },
            { type = "list_item", text = "Hiding players can no longer go near the Seeker’s waiting room.", level = 0 },
            { type = "dev_note", text = "There was an emergent tactic where hiders would place a bunch of traps near the seekers’ entrance, preventing them from leaving.", level = 1 },
            { type = "h3", text = "Dungeons and Raids" },
            { type = "list_item", text = "Magisters’ Terrace", level = 0 },
            { type = "list_item", text = "Addressed an issue where Degentrius’ Devouring Entropy could damage players who were immune to it.", level = 1 },
            { type = "list_item", text = "Windrunner Spire", level = 0 },
            { type = "list_item", text = "Addressed an issue where Commander Kroluk could melee after finishing casting Bladestorm.", level = 1 },
            { type = "list_item", text = "The Voidspire", level = 0 },
            { type = "list_item", text = "Crown of the Cosmos", level = 1 },
            { type = "list_item", text = "Gravity Collapse damage reduced by 10%.", level = 2 },
            { type = "hr" },
            { type = "h3", text = "April 22, 2026" },
            { type = "h3", text = "Characters" },
            { type = "list_item", text = "Fixed a bug that could cause some Night Elf characters to be missing the intended Linen Blindfold option they previously chose.", level = 0 },
            { type = "h3", text = "Classes" },
            { type = "list_item", text = "Death Knight", level = 0 },
            { type = "list_item", text = "Resolved an issue causing the Commander of the Dead damage increase aura to be applied to Death Knights.", level = 1 },
            { type = "list_item", text = "Evoker", level = 0 },
            { type = "list_item", text = "Preservation", level = 1 },
            { type = "list_item", text = "Fixed an issue where Dream Breath was not being stored in Stasis.", level = 2 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Holy", level = 1 },
            { type = "list_item", text = "Fixed a bug that could cause Holy Paladins to do less damage than intended.", level = 2 },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "list_item", text = "Fixed a bug that prevented the expected audio from playing when a Rogue enters stealth.", level = 1 },
            { type = "h3", text = "Decor Duel" },
            { type = "list_item", text = "Fixed a bug that could prevent Decor Duel participants from receiving base Illusionary Coin rewards by incorrectly evaluating them to be AFK.", level = 0 },
            { type = "list_item", text = "Humanoid tracking abilities no longer reveal players in Decor Duel.", level = 0 },
            { type = "list_item", text = "Achievements earned in Decor Duel are now account-wide, as intended.", level = 0 },
            { type = "h3", text = "Dungeons and Raids" },
            { type = "list_item", text = "Addressed an issue where Lindormi’s Guidance could be applied to players outside of Mythic+ dungeons.", level = 0 },
            { type = "list_item", text = "March on Quel’Danas", level = 0 },
            { type = "list_item", text = "Midnight Falls", level = 1 },
            { type = "list_item", text = "Resolved issues with Torchbearer failing to prevent players from receiving applications of Midnight or failing to remove applications of Midnight.", level = 2 },
            { type = "h3", text = "Items" },
            { type = "list_item", text = "Addressed an issue preventing sockets from being added to Champion items obtained from Midnight Renown vendors.", level = 0 },
            { type = "list_item", text = "Fixed an issue where acquiring a Nebulous Voidcore with Thalassian Tokens of Merit would cause Decimus to only grant one of his two weekly Nebulous Voidcores upon quest turn-in.", level = 0 },
            { type = "dev_note", text = "Players who have two Nebulous Voidcores in their currency window while showing “Season Maximum: 1/2” can now safely complete any of Decimus’s quests again to receive their missing Nebulous Voidcore.", level = 1 },
            { type = "h3", text = "Professions" },
            { type = "list_item", text = "Adjusted the cost of Thalassian Competitor’s Chain Tunic to 5 Heraldry (was 4) to be in line with other crafted PvP chestpieces.", level = 0 },
            { type = "h3", text = "Quests" },
            { type = "list_item", text = "The Ancient Visionstone can once again be interacted with for the Harandar repeatable legends quests “The Story of the Echoless Flame” and “The Story of Russula’s Outreach”.", level = 0 },
            { type = "list_item", text = "Fixed a bug where the daily quest “Ephemeral Masquerade” appeared to be a low-level quest, rather than the intended blue exclamation point.", level = 0 },
            },
        },
        ["2026-06-03-the-burning-crusade-hotfixes-updated-june-2-a1b072c8fc"] = {
            id = "2026-06-03-the-burning-crusade-hotfixes-updated-june-2-a1b072c8fc",
            post_key = "a1b072c8fc",
            title = "The Burning Crusade Hotfixes - Updated June 2",
            category = "The Burning Crusade Classic (US)",
            timestamp = 1780454872,
            url = "https://us.forums.blizzard.com/en/wow/t/2227871/1",
            content = {
            { type = "h2", text = "HOTFIXES" },
            { type = "h3", text = "June 2, 2026" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Classes", level = 0 },
            { type = "list_item", text = "Death Knight", level = 1 },
            { type = "list_item", text = "Blood", level = 2 },
            { type = "list_item", text = "Bloodworms again have avoidance of area-of-effect spells.", level = 3 },
            { type = "list_item", text = "Player versus Player", level = 0 },
            { type = "list_item", text = "Following an Arena match, the user interface now displays the pre-match Matchmaking Ratings (MMR) for each team.", level = 1 },
            { type = "dev_note", text = "Our goal is to provide more information, so that players can better contextualize their changing MMR.", level = 2 },
            { type = "hr" },
            { type = "h3", text = "April 1, 2026" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Significantly increased the amount of Honor earned in all battlegrounds.", level = 0 },
            { type = "h3", text = "February 20, 2026" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Fixed an issue that was causing the Karazhan Chess Event to run much faster than intended, allowing Medivh to cheat more often than he should. Sneaky Medivh!", level = 0 },
            { type = "h3", text = "February 12, 2026" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Updated the Communal Flamewrought Keys to be usable by either faction if the character is Friendly with Honor Hold/Thrallmar.", level = 0 },
            { type = "list_item", text = "[With realm restarts] Fixed a bug that caused enemies to be less armored against physical attacks than intended.", level = 0 },
            { type = "h3", text = "February 4, 2026" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "The book ‘Soothsaying for Dummies’ has been re-enabled.", level = 0 },
            { type = "list_item", text = "Fixed an issue that could prevent warlock players from being able to complete the quest “What is Love”.", level = 0 },
            { type = "list_item", text = "Fixed a bug where The Prophet Skeram would incorrectly purge buffs from players when transitioning between phases.", level = 0 },
            { type = "h3", text = "February 3, 2026" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Player-characters who were incorrectly granted the 150 Epic riding skill have been reverted to riding skill 75.", level = 0 },
            { type = "h3", text = "January 27, 2026" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Fixed a rare bug where characters who received a Level 58 Character Boost did not learn all their spells.", level = 0 },
            { type = "list_item", text = "Book “Soothsaying for Dummies”, used to re-choose profession specializations for Leatherworking and Engineering, has been temporarily disabled while we resolve an issue with it granting the wrong specialization.", level = 0 },
            { type = "dev_note", text = "We’re aiming to have the book reenabled in the not-too-distant future and will post a hotfix note when that happens.", level = 1 },
            { type = "list_item", text = "Fixed an issue where raid frames were not correctly displaying whether a player was in-range or not.", level = 0 },
            { type = "list_item", text = "Fixed an issue where pets with auto-cast spells would cause client performance to degrade over time.", level = 0 },
            { type = "list_item", text = "Fixed an issue that caused the pre-expansion event to disable briefly.", level = 0 },
            { type = "h3", text = "January 16, 2026" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Fixed an issue where Blackrock Spire only allowed 5 players to enter.", level = 0 },
            { type = "list_item", text = "Fixed a bug preventing the quest “The First and Last” from starting for eligible players.", level = 0 },
            { type = "list_item", text = "Cleansed Songflowers now apply their buff to the clicking player, not the player’s target.", level = 0 },
            { type = "list_item", text = "Paladins should now be able to learn Consecration from their trainer as intended.", level = 0 },
            { type = "list_item", text = "Shamans who were unable to learn Two-Handed Maces and Two-Handed Axes from the weapon trainer should again be able to.", level = 0 },
            { type = "dev_note", text = "Players may need to log out and back in to pick up this fix.", level = 1 },
            { type = "list_item", text = "Player versus Player", level = 0 },
            { type = "list_item", text = "The current active increase to Honor gains is now 150% (was a 100% bonus).", level = 1 },
            { type = "list_item", text = "Added level 51-60 versions of the “For Great Honor” (Horde) and “Concerted Effort” (Alliance) quests.", level = 1 },
            { type = "dev_note", text = "Soon after launching the Burning Crusade pre-expansion patch, we could see that PvP needed an additional increase in rate of gearing. These quests award 400 Honor (at level 60) when handed in, as well as experience for players from levels 51-59. These quests do not require Eye of the Storm, and their text will soon be updated to reflect that. When the Dark Portal opens, these quests will no longer be available, and the level 61-70 versions of these quests will become available.", level = 1 },
            { type = "h3", text = "January 14, 2025" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Restored character Boost services after a brief outage.", level = 0 },
            { type = "list_item", text = "Enabled Arena Skirmishes, as intended.", level = 0 },
            { type = "list_item", text = "Fixed an issue that caused Addons to be unintentionally throttled.", level = 0 },
            { type = "list_item", text = "Returned the Chronoboon Displacer to its adjusted cost of 1 gold and stack size of 10.", level = 0 },
            },
        },
