        ["2026-05-27-updated-may-27-add-the-omnium-folio-to-your-library-of-tools-against-t-824ca0fb7d"] = {
            id = "2026-05-27-updated-may-27-add-the-omnium-folio-to-your-library-of-tools-against-t-824ca0fb7d",
            post_key = "824ca0fb7d",
            title = "[Updated May 27] Add the Omnium Folio to Your Library of Tools Against the Void",
            category = "Blogs (US)",
            timestamp = 1779925553,
            url = "https://news.blizzard.com/en-us/article/24277442/updated-may-27-add-the-omnium-folio-to-your-library-of-tools-against-the-void",
            content = {
            { type = "p", text = "*Article revised on May 27. Some rune tooltips have been updated." },
            { type = "p", text = "Join Magister Umbric and Grand Magister Rommath to restore the reawakened Sunstrider Omnium, an ancient elven relic once created by Dath’remar Sunstrider to study and preserve the schools of magic." },
            { type = "p", text = "Once unlocked, the Omnium Folio grants access to potent runes for battle; continue activities to imbue additional power and unlock its full potential against the forces of the Void. These rune powers will be available to players throughout the rest of the Midnight expansion." },
            { type = "hr" },
            { type = "h2", text = "UNLOCK AND CHOOSE YOUR RUNES TO EMPOWER THE OMNIUM FOLIO" },
            { type = "p", text = "Magister Umbric and Grand Magister Rommath have some tasks for you. They need help repairing and restoring the newly reawakened Sunstrider Omnium. Once their initial tasks are complete, you’ll unlock the Omnium Folio and begin your journey toward gaining access to its full power." },
            { type = "p", text = "Opening the Omnium Folio by clicking on its icon on the mini-map interface will provide you with many options as you work to unlock the power within. You’ll be able to choose one core rune and one rune from each subsequent row as additional enhancements. These runes can be changed at any time outside of combat and are unlocked by completing the Seeking Knowledge quest each week. Each completion will provide a Mote of Omnial Inquiry." },
            { type = "p", text = "Mote of Omnial Inquiry: Each Mote of Omnial Inquiry can be used to empower the runes within your Omnium Folio." },
            { type = "p", text = "These enhancements enable new passive abilities to help you as you face the Void." },
            { type = "image", width = 568, height = 420, u = 0.554688, v = 0.820312, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-05-27-updated-may-27-add-the-omnium-folio-to-your-library-of-tools-against-t-824ca0fb7d\\image-1.jpg" },
            { type = "h2", text = "ROW 1: CORE RUNES" },
            { type = "p", text = "Rune of Void-Touched Orbs Core Rune Every 10 seconds you attract a Void-Touched orb, up to 5. Damaging an enemy sends all of the Orbs at them dealing Cosmic damage per Orb. Your healing spells send all of the Orbs to the most injured nearby ally, healing them per Orb." },
            { type = "p", text = "Rune of Unleashed Fire Core Rune Your spells and abilities have a very high chance to unleash the power of flame, dealing Fire damage to an enemy or restoring health to the most injured nearby ally." },
            { type = "h2", text = "ROW 2" },
            { type = "p", text = "Rune of Self-Mending When your Core Rune deals damage or healing, you are healed if you are below 75% health." },
            { type = "p", text = "Rune of Void-Tainted Shell Suffering more than 10% of your maximum health in a single hit grants you a shield that absorbs damage for 10 seconds but also inflicts damage to you every one second. This effect can only occur once every 30 seconds." },
            { type = "p", text = "Rune of Lynxlike Reflexes Taking damage grants 115 Speed for 10 seconds. Cannot occur more than once every 30 seconds." },
            { type = "h2", text = "ROW 3" },
            { type = "p", text = "Rune of Lingering Lingering RuneYour Core Rune deals additional Cosmic damage to enemies, or additional healing to allies, over 8 seconds. Your Core Rune now favors hitting the targets that are unaffected by Rune of Lingering." },
            { type = "h2", text = "ROW 4" },
            { type = "p", text = "Rune of Critical Power When your Core Rune activates, gain Critical Strike for 10 seconds. Multiple applications may overlap." },
            { type = "p", text = "Rune of Burning Haste The effects of your Core Rune increase your Haste rating. This effect may overlap." },
            { type = "p", text = "Rune of Masterful Cunning The effects of your Core Rune increase your Mastery rating. This effect may overlap." },
            { type = "p", text = "Rune of Versatile Warrior The effects of your Core Rune increase your Versatility rating. This effect may overlap." },
            { type = "h2", text = "ROW 5" },
            { type = "p", text = "Rune of Overload The damage and healing of your Core Rune is increased by 100%" },
            { type = "p", text = "Rune of Residual Energy The damage and healing of your your Rune of Lingering is increased by 100%." },
            { type = "p", text = "Rune of Echoes Your Core Rune leaves an echoing curse on your target for 10 seconds that accumulates 50% of all damage and healing done to the target by your Core Rune and Your Rune of Lingering. When the curse expires, all accumulated damage or healing is dealt to the target." },
            { type = "p", text = "Upon completion of all five Seeking Knowledge quests, players will receive the Housing decor item—Sunstrider Omnium Simulacrum." },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-05-27-updated-may-27-add-the-omnium-folio-to-your-library-of-tools-against-t-824ca0fb7d\\image-2.jpg" },
            { type = "hr" },
            { type = "p", text = "You can learn more about the Sunstrider Omnium and its history by speaking with Magister Umbric, Grand Magister Rommath, or Custodian Veldharin in the Lycaneum on the Isle of Quel’Danas" },
            { type = "p", text = "We’ll see you there!" },
            },
        },
        ["2026-05-27-add-the-omnium-folio-to-your-library-of-tools-against-the-void-a6c06515d5"] = {
            id = "2026-05-27-add-the-omnium-folio-to-your-library-of-tools-against-the-void-a6c06515d5",
            post_key = "a6c06515d5",
            title = "Add the Omnium Folio to Your Library of Tools Against the Void",
            category = "General Discussion (EU)",
            timestamp = 1779901323,
            url = "https://eu.forums.blizzard.com/en/wow/t/620224/1",
            content = {
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-05-27-add-the-omnium-folio-to-your-library-of-tools-against-the-void-a6c06515d5\\image-1.jpg" },
            { type = "p", text = "Unlock the reawakened Sunstrider Omnium and wield the Omnium Folio, a runic ledger available in the Midnight: Revelations content update, then take part in weekly activities to imbue runes and unlock its full potential in the fight against the Void." },
            { type = "p", text = "View Full Article" },
            },
        },
