            { type = "list_item", text = "Fixed an issue that caused Beacon of Light to sometimes not transfer healing from Holy Light or Flash of Light.", level = 2 },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "list_item", text = "Assassination", level = 1 },
