        ["2026-05-22-now-available-for-testing-d1baf7d81e"] = {
            id = "2026-05-22-now-available-for-testing-d1baf7d81e",
            post_key = "d1baf7d81e",
            title = "Now Available For Testing",
            category = "Mists of Pandaria Classic 5.5.4 PTR (US)",
            timestamp = 1779485033,
            url = "https://us.forums.blizzard.com/en/wow/t/2293254/1",
            content = {
            { type = "p", text = "Welcome to the Public Test Realm (PTR) for Mists of Pandaria Classic: Siege of Orgrimmar, patch 5.5.4." },
            { type = "p", text = "Patch 5.5.4 will introduce several updates including the Timeless Isle zone, the Proving Grounds scenarios, the conclusion of the Legendary questline, new world bosses, updates to the Celestial Dungeons, and the Siege of Orgrimmar raid." },
            { type = "p", text = "Please note that some of these features are not available for test yet, and will be added to the PTR over the next few weeks." },
            { type = "h1", text = "NOW AVAILABLE FOR TESTING" },
            { type = "h3", text = "New Zone: Timeless Isle" },
            { type = "list_item", text = "A mysterious island, lost for millennia to the currents of time, has emerged from the mists off the eastern coast of Jade Forest.", level = 0 },
            { type = "list_item", text = "The Timeless Isle is inhabited by all manner of strange and powerful creatures that will test the mettle of solo explorers, but great rewards await the brave and skillful: epic loot, bind-to-account gear, Mogu Runes of Fate, pets, mounts, toys, and much more.", level = 1 },
            { type = "list_item", text = "The Isle is filled with secrets and mysteries, many of which dynamically become available to explorers. You may encounter hidden treasure chests, rare and elite creatures, and events across the isle.", level = 1 },
            { type = "list_item", text = "You can also join the ranks of the Ordon, the faithful of Ordos, and gain the ability to engage in PvP with everyone - even your own faction!", level = 1 },
            { type = "list_item", text = "The Timeless Isle is home to five new world raid bosses.", level = 0 },
            { type = "list_item", text = "Players may face each of the four Celestials in a trial of combat.", level = 1 },
            { type = "list_item", text = "Heroes who have earned the legendary cloak from Wrathion may access the sanctum of the fiery Yaungol demigod Ordos, atop the Timeless Isle.", level = 1 },
            { type = "list_item", text = "To gain access to this zone, visit your faction’s shrine in the Vale of Eternal Blossoms.", level = 0 },
            { type = "h3", text = "Legendary Questline" },
            { type = "list_item", text = "Wrathion’s final quests are now available for dedicated heroes who have fought on his behalf throughout the pandaren campaign.", level = 0 },
            { type = "list_item", text = "Complete Wrathion’s final tasks on the Timeless Isle and defeat Garrosh Hellscream in the Siege of Orgrimmar Raid to upgrade your celestial cloak to Legendary quality!", level = 1 },
            { type = "list_item", text = "Only players equipped with a Legendary cloak can reach the Sanctum of Ordos atop the Timeless Isle. (This privilege extends account-wide.)", level = 1 },
            { type = "list_item", text = "Note: This questline will not be completable until Siege of Orgrimmar raid releases on PTR.", level = 1 },
            { type = "list_item", text = "To continue this questline, meet Wrathion at the Tavern in the Mists in the Veiled Stair.", level = 0 },
            { type = "h1", text = "FUTURE TESTING" },
            { type = "p", text = "The following features are not currently available for testing." },
            { type = "list_item", text = "The Siege of Orgrimmar raid", level = 0 },
            { type = "list_item", text = "Celestial Dungeon updates", level = 0 },
            { type = "list_item", text = "Challenge Mode updates", level = 0 },
            { type = "list_item", text = "Proving Grounds", level = 0 },
            { type = "h3", text = "We’re planning to run our first Siege of Orgrimmar raid playtest:" },
            { type = "list_item", text = "Friday, April 24 - Sunday, April 26", level = 0 },
            { type = "h1", text = "KNOWN ISSUES" },
            { type = "p", text = "We are tracking the following known issues, and we are working to address them." },
            { type = "h3", text = "General" },
            { type = "list_item", text = "Heirloom items levels don’t increase with character level, although the stats do increase.", level = 0 },
            { type = "h3", text = "Timeless Isle" },
            { type = "list_item", text = "Treasure chests are not lootable.", level = 0 },
            { type = "h3", text = "User Interface" },
            { type = "list_item", text = "Nameplates are using the modern WoW version instead of the Classic one.", level = 0 },
            { type = "list_item", text = "The Transmog UI won’t be available during the first few weeks of the PTR. Trying to access it will cause LUA errors.", level = 0 },
            { type = "list_item", text = "There is an extra “Help” micro button on the action bar, causing the bar to cover one of the bag icons.", level = 0 },
            { type = "list_item", text = "There are random texture strings attached to weapons on the Character Selection screen.", level = 0 },
            },
        },
        ["2026-05-22-wow-weekly-fungarian-mischief-looms-in-midnight-and-more-matches-in-md-a992a92e4a"] = {
