            { type = "list_item", text = "Soul Harvester: Fixed an issue where consuming Nightfall with Malefic Grasp would not activate Wicked Reaping.", level = 2 },
            { type = "list_item", text = "Demonology", level = 1 },
            { type = "list_item", text = "Fixed an issue where Fel Armaments would reduce the cooldown of Felstorm by 20 seconds, rather than the intended 10 seconds.", level = 2 },
            { type = "h3", text = "Delves" },
            { type = "list_item", text = "The Darkway", level = 0 },
            { type = "list_item", text = "Corrupted Leyline will no longer sometimes continue to cast Detected! after it’s out of range.", level = 1 },
            { type = "list_item", text = "The Shadow Enclave", level = 0 },
            { type = "list_item", text = "Fixed an issue where characters could lose the ability to strafe after picking up a mirror.", level = 1 },
            { type = "h3", text = "Items and Rewards" },
            { type = "list_item", text = "Fixed a Great Vault display bug where the World Row indicated an item level of 272 for the Tier 5 Ritual Site, instead of the intended 269 item level.", level = 0 },
            { type = "h3", text = "Player versus Player" },
            { type = "list_item", text = "Demon Hunter", level = 0 },
            { type = "list_item", text = "Fixed an issue that prevented the target throw effect from being available while using Illidan's Grasp.", level = 1 },
            { type = "list_item", text = "Havoc", level = 1 },
            { type = "list_item", text = "Fixed an issue that caused Consume Magic to remove an additional Magic effect from the primary target when the Blood Moon PvP Talent was selected.", level = 2 },
            { type = "h3", text = "Quests" },
            { type = "list_item", text = "Resolved an issue where players who completed the quest \"The Legend of Aln'Sharan\" could not gather them on alts without completing the quest first.", level = 0 },
            { type = "hr" },
            { type = "h3", text = "April 24, 2026" },
            { type = "h3", text = "Achievements" },
            { type = "list_item", text = "Midnight Keystone Myth - Season One is now available to players who attained a Mythic+ Rating of at least 3400 during Midnight Season 1.", level = 0 },
            { type = "h3", text = "Characters" },
            { type = "list_item", text = "Pandaren characters who boost during the intro sequence will now be able to port to their houses.", level = 0 },
            { type = "h3", text = "Classes" },
            { type = "list_item", text = "Death Knight", level = 0 },
            { type = "list_item", text = "Unholy", level = 1 },
            { type = "list_item", text = "Festering Scythe is now an aura on the player, resolving issues that occur when extending the duration of plagues.", level = 2 },
            { type = "dev_note", text = "The underlying issue here was proving to be problematic for a number of reasons and we felt like this would be the safest approach for now.", level = 3 },
            { type = "list_item", text = "Resolved an issue causing Magus of the Dead to not take action immediately on spawn.", level = 2 },
            { type = "list_item", text = "Resolved an issue causing Forbidden Knowledge Rank 4 to activate less than stated.", level = 2 },
            { type = "list_item", text = "Resolved an issue causing Unholy Devotion to grant Haste in addition to attack speed and energy regeneration.", level = 2 },
            { type = "list_item", text = "Disease Cloud is now cast by the Abomination, resolving issues such as it not interacting with pet scaling talents.", level = 2 },
            { type = "list_item", text = "Demon Hunter", level = 0 },
            { type = "list_item", text = "Devourer", level = 1 },
            { type = "list_item", text = "Fixed an issue causing the Single-Button Assistant and Assisted Highlight to not recommend Collapsing Star outside of melee range.", level = 2 },
            { type = "list_item", text = "Vengeance", level = 1 },
            { type = "list_item", text = "Fixed an issue that caused Metamorphosis to be put on cooldown when Last Resort's effect triggered.", level = 2 },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Marksmanship", level = 1 },
            { type = "list_item", text = "Corrected an issue where Unbreakable Bond could give the damage reduction effect to the hunter rather than their pet.", level = 2 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Frost", level = 1 },
            { type = "list_item", text = "Fixed an issue causing Hand of Frost (Rank 2) to not provide the correct percent chance increase per stack of Shatter.", level = 2 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Holy", level = 1 },
            { type = "list_item", text = "Fixed an issue that caused Holy Armaments to significantly impact framerates.", level = 2 },
            { type = "list_item", text = "Priest", level = 0 },
            { type = "list_item", text = "Shadow", level = 1 },
            { type = "list_item", text = "Voidweaver: Fixed an issue causing Overwhelming Shadows to increase the damage of Mind Blast.", level = 2 },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "list_item", text = "Trickster: Fixed an issue that caused Cloud Cover's effect to cost 30 Energy to activate.", level = 1 },
            { type = "list_item", text = "Trickster: Cloud Cover's visual effect is now only visible to the caster in all circumstances.", level = 1 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Affliction", level = 1 },
            { type = "list_item", text = "Fixed an issue where Jinx would not function if Foul Mouth was not talented.", level = 2 },
            { type = "list_item", text = "Demonology", level = 1 },
            { type = "list_item", text = "Fixed an issue where Demonic Gateway would benefit Hellbent Commander.", level = 2 },
            { type = "h3", text = "Delves" },
            { type = "list_item", text = "Valeera is no longer unwilling to attack Poison Dart Frog or Giant Cursed Bullfrog.", level = 0 },
            { type = "list_item", text = "Atal’Aman", level = 0 },
            { type = "list_item", text = "Adjusted the placement of several out-of-range Sanctified Banners in two story variants.", level = 1 },
            { type = "list_item", text = "The Darkway", level = 0 },
            { type = "list_item", text = "The Corrupted Leyline will no longer sometimes continue to cast Detected! after being out of its range.", level = 1 },
            { type = "h3", text = "Dungeons and Raids" },
            { type = "list_item", text = "Maisara Caverns", level = 0 },
            { type = "list_item", text = "Addressed an issue where players could remain in combat after defeating Vordaza.", level = 1 },
            { type = "h3", text = "Housing" },
            { type = "list_item", text = "Decorative Dornogal Opals (small, medium and large) are now available for purchase from the Disguised Decor Duel Vendor in Silvermoon.", level = 0 },
            { type = "h3", text = "Player versus Player" },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Marksmanship", level = 1 },
            { type = "list_item", text = "Precise Shots now benefits Kill Shot and Black Arrow at 50% effectiveness in PvP combat.", level = 2 },
            { type = "list_item", text = "Black Arrow damage reduced by 30% in PvP combat.", level = 2 },
            { type = "list_item", text = "All damage reduced by 10% in PvP combat.", level = 2 },
            { type = "dev_note", text = "Several talent changes in 12.0.5 led to Marksmanship overperforming in PvP. These updates target changes to Black Arrow and their overall damage to account for the new interactions and reduce their effectiveness at both burst damage and overall pressure.", level = 3 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Mass Invisibility will no longer target players carrying the Deephaul Crystal in Deephaul Ravine.", level = 1 },
            { type = "list_item", text = "Priest", level = 0 },
            { type = "list_item", text = "Fixed an issue causing Cyclone to be able to be applied while a Priest has Psychic Shroud active.", level = 1 },
            { type = "h3", text = "Quests" },
            { type = "list_item", text = "Fixed an issue where some Alliance players were unable to see the \"Heavy Anchor\" for \"The Fragrance of the Dunes\" quest.", level = 0 },
            { type = "list_item", text = "Fixed an issue causing players to be unable to turn in Nebulous Voidcores to Decimus while on the quest “Artifice of Aggression”.", level = 0 },
            { type = "list_item", text = "Fixed an issue that could cause Lorna Crowley to phase out when engaged for the Arcantina quest \"A Generational Moment\".", level = 0 },
            { type = "hr" },
            { type = "h3", text = "April 23, 2026" },
            { type = "h3", text = "Classes" },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Marksmanship", level = 1 },
            { type = "list_item", text = "Corrected an issue where players could gain double the benefit of Pathfinding or Endurance Training when using the Unbreakable Bond talent in combination with the Cunning or Tenacious talents.", level = 2 },
            { type = "list_item", text = "Cunning or Tenacity pets should no longer sometimes lose their pet passive bonuses of Endurance Training and Pathfinding when changing between the Cunning and Tenacity talent choice node.", level = 2 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Fixed an issue where Frequent Traveler would not function when using another Warlock's Demonic Gateway.", level = 1 },
            { type = "list_item", text = "Diabolist: Fixed an issue where Abyssal Dominion would not match the duration of Demonic Tyrant with Reign of Tyranny talented.", level = 1 },
            { type = "list_item", text = "Affliction", level = 1 },
            { type = "list_item", text = "Fixed an issue where Blight of Weakness and Tongues would not properly display on the Cooldown Manager.", level = 2 },
            { type = "list_item", text = "Destruction", level = 1 },
            { type = "list_item", text = "Removed several spells from the Cooldown Manager, as they are no longer present in-game.", level = 2 },
            { type = "h3", text = "Décor Duel" },
            { type = "list_item", text = "Hiding players can no longer go near the Seeker's waiting room.", level = 0 },
            { type = "dev_note", text = "There was an emergent tactic where hiders would place a bunch of traps near the seekers’ entrance, preventing them from leaving.", level = 1 },
            { type = "h3", text = "Dungeons and Raids" },
            { type = "list_item", text = "Magisters' Terrace", level = 0 },
            { type = "list_item", text = "Addressed an issue where Degentrius' Devouring Entropy could damage players who were immune to it.", level = 1 },
            { type = "list_item", text = "Windrunner Spire", level = 0 },
            { type = "list_item", text = "Addressed an issue where Commander Kroluk could melee after finishing casting Bladestorm.", level = 1 },
            { type = "list_item", text = "The Voidspire", level = 0 },
            { type = "list_item", text = "Crown of the Cosmos", level = 1 },
            { type = "list_item", text = "Gravity Collapse damage reduced by 10%.", level = 2 },
            { type = "hr" },
            { type = "h3", text = "April 22, 2026" },
            { type = "h3", text = "Characters" },
            { type = "list_item", text = "Fixed a bug that could cause some Night Elf characters to be missing the intended Linen Blindfold option they previously chose.", level = 0 },
            { type = "h3", text = "Classes" },
            { type = "list_item", text = "Death Knight", level = 0 },
            { type = "list_item", text = "Resolved an issue causing the Commander of the Dead damage increase aura to be applied to Death Knights.", level = 1 },
            { type = "list_item", text = "Evoker", level = 0 },
            { type = "list_item", text = "Preservation", level = 1 },
            { type = "list_item", text = "Fixed an issue where Dream Breath was not being stored in Stasis.", level = 2 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Holy", level = 1 },
            { type = "list_item", text = "Fixed a bug that could cause Holy Paladins to do less damage than intended.", level = 2 },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "list_item", text = "Fixed a bug that prevented the expected audio from playing when a Rogue enters stealth.", level = 1 },
            { type = "h3", text = "Decor Duel" },
            { type = "list_item", text = "Fixed a bug that could prevent Decor Duel participants from receiving base Illusionary Coin rewards by incorrectly evaluating them to be AFK.", level = 0 },
            { type = "list_item", text = "Humanoid tracking abilities no longer reveal players in Decor Duel.", level = 0 },
            { type = "list_item", text = "Achievements earned in Decor Duel are now account-wide, as intended.", level = 0 },
            { type = "h3", text = "Dungeons and Raids" },
            { type = "list_item", text = "Addressed an issue where Lindormi's Guidance could be applied to players outside of Mythic+ dungeons.", level = 0 },
            { type = "list_item", text = "March on Quel’Danas", level = 0 },
            { type = "list_item", text = "Midnight Falls", level = 1 },
            { type = "list_item", text = "Resolved issues with Torchbearer failing to prevent players from receiving applications of Midnight or failing to remove applications of Midnight.", level = 2 },
            { type = "h3", text = "Items" },
            { type = "list_item", text = "Addressed an issue preventing sockets from being added to Champion items obtained from Midnight Renown vendors.", level = 0 },
            { type = "list_item", text = "Fixed an issue where acquiring a Nebulous Voidcore with Thalassian Tokens of Merit would cause Decimus to only grant one of his two weekly Nebulous Voidcores upon quest turn-in.", level = 0 },
            { type = "dev_note", text = "Players who have two Nebulous Voidcores in their currency window while showing \"Season Maximum: 1/2\" can now safely complete any of Decimus's quests again to receive their missing Nebulous Voidcore.", level = 1 },
            { type = "h3", text = "Professions" },
            { type = "list_item", text = "Adjusted the cost of Thalassian Competitor's Chain Tunic to 5 Heraldry (was 4) to be in line with other crafted PvP chestpieces.", level = 0 },
            { type = "h3", text = "Quests" },
            { type = "list_item", text = "The Ancient Visionstone can once again be interacted with for the Harandar repeatable legends quests \"The Story of the Echoless Flame\" and \"The Story of Russula's Outreach\".", level = 0 },
            { type = "list_item", text = "Fixed a bug where the daily quest \"Ephemeral Masquerade\" appeared to be a low-level quest, rather than the intended blue exclamation point.", level = 0 },
            },
        },
        ["2026-05-19-midnight-revelations-1207-ptr-development-notes-9057c51071"] = {
            id = "2026-05-19-midnight-revelations-1207-ptr-development-notes-9057c51071",
            post_key = "9057c51071",
            title = "Midnight: Revelations 12.0.7 PTR Development Notes",
            category = "Midnight: Revelations Public Test Realm (EU)",
            timestamp = 1779234321,
            url = "https://eu.forums.blizzard.com/en/wow/t/617999/1",
            content = {
            { type = "h1", text = "MIDNIGHT: REVELATIONS 12.0.7 PTR DEVELOPMENT NOTES" },
            { type = "hr" },
            { type = "p", text = "Take a look at what’s in the PTR this week." },
            { type = "h2", text = "GET READY FOR A SHOWDOWN" },
            { type = "p", text = "Facing the forces of the Void in Void Assaults and Ritual Sites isn’t enough to stop their machinations. To cut the threat off at its source, you’ll need to hunt down the leaders behind these brutal attacks on Azeroth. Track them through a portal in Voidstorm leading to two new locations:" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-05-19-midnight-revelations-1207-ptr-development-notes-9057c51071\\image-1.jpg" },
            { type = "p", text = "Naigtal: A fungal, arcane-rich world now occupied by an insidious ethereal faction known as the Hal’hadar." },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-05-19-midnight-revelations-1207-ptr-development-notes-9057c51071\\image-2.jpg" },
            { type = "p", text = "Val: An icy world once inhabited by the Legion where the Domanaar Imperator Pertinax has established his bastion of power." },
            { type = "p", text = "The portal to these worlds is unstable and switches destinations every few days, bringing a rotating set of challenges and experiences. Players can undertake World Quests, defeat rare enemies, take part in events, and ultimately have a showdown with the leaders as world bosses." },
            { type = "h2", text = "GAIN NEW POWER WITH THE OMNIUM FOLIO" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-05-19-midnight-revelations-1207-ptr-development-notes-9057c51071\\image-3.jpg" },
            { type = "p", text = "Join Magister Umbric and Grand Magister Rommath on a mission to reconfigure and restore the Sunstrider Omnium. This ancient elven relic was originally created by Dath’remar Sunstrider to study and observe the various schools of magic and to serve as an academic repository. After years of silence, the Sunstrider Omnium has now reawakened, unsettling the Magisters and sowing disarray among them." },
            { type = "p", text = "Once unlocked, you’ll be entrusted with the Omnium Folio, a runic ledger containing powerful runes of power you can use in battle. Continue taking part in weekly activities to imbue more runes—customizing these initial runes and unlocking their maximum potential to aid you in the fight against the Void." },
            { type = "h2", text = "GO LOREWALKING WITH THE LOA" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-05-19-midnight-revelations-1207-ptr-development-notes-9057c51071\\image-4.jpg" },
            { type = "p", text = "Experience the lore of the loa with Assistant Lorewalker Li Li. You’ll dive deeper into the stories of the Zandalari, Drakkari, Gurubashi, and Darkspear trolls." },
            { type = "h2", text = "HELP LOA SPEAKER BREK HATCH JAN’ALAI’S NEW EGGS" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-05-19-midnight-revelations-1207-ptr-development-notes-9057c51071\\image-5.jpg" },
            { type = "p", text = "With the return of Jan’alai, Loa of Fire comes a return to past traditions. She’s ready to bring a new clutch of eggs into the world but Loa Speaker Brek requires assistance with the ceremony and with ensuring all the Loa’s young are released safely from their eggs. Be a part of welcoming the first of her offspring and protecting them as they take their first steps." },
            { type = "h2", text = "BEGIN THE NEXT CHAPTER WITH ZUL’JAN" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-05-19-midnight-revelations-1207-ptr-development-notes-9057c51071\\image-6.jpg" },
            { type = "p", text = "When the haranir call for a special gathering, Zul’jan attends as the Amani representative—only to be drawn into an ancient mystery surrounding the legacy of the Amani trolls. Join him and his uncle Kinduru on their journey of discovery to uncover the truth. This content will arrive after the release of the update." },
            { type = "h2", text = "HOUSING" },
            { type = "list_item", text = "Lighting is now available outdoors! You can now add lights to your plot. Lighting Decor will have certain restraints outdoors that they do not have indoors.", level = 0 },
            { type = "list_item", text = "Two lights cannot overlap and will become unplaceable when too close. Light indicator radius visuals will appear when the lights are too close and will turn red when overlapping.", level = 1 },
            { type = "list_item", text = "Over 100 new common decor can be found on existing Neighborhood vendors.", level = 0 },
            { type = "list_item", text = "Known Issue: We are aware of the floor-changing bug and looking to hotfix it in the very near future.", level = 0 },
            { type = "h2", text = "ITEMS" },
            { type = "dev_note", text = "We identified issues with collecting and tracking the amount of Luminous Dust a player would receive which sometimes resulted in a mis-match between the number of moths a player had found and the amount of Luminous Dust they had received on their account. This caused some players to not be able to acquire all of the Mothkeeper’s rewards. We have shifted to using quests to give rewards instead which will allow those who experienced this mismatch to claim missing rewards.", level = 0 },
            { type = "list_item", text = "Rebuilt how the Moth Hunt feature in Harandar gives rewards. Players will not lose any existing progress on their moth collection.", level = 1 },
            { type = "list_item", text = "Glowing Moths no longer give Luminous Dust when collected, and Luminous Dust has been removed from players’ bags.", level = 2 },
            { type = "list_item", text = "Mothkeeper Wew’tam no longer sells items for Luminous Dust, instead, Mothkeeper Wew’tam now has a quest to receive a reward for every 10 moths gathered on an account.", level = 2 },
            { type = "list_item", text = "These quests will only be visible to players who have reached the collection requirements to get a specific reward, but have not already acquired it.", level = 3 },
            { type = "list_item", text = "Extra copies of decor may still be purchased from Mothkeeper Wew’tam for Voidlight Marl after receiving your first one.", level = 2 },
            { type = "list_item", text = "Mothkeeper Wew’tam now has dialogue options explaining what rewards she gives for collecting different amounts of moths.", level = 2 },
            { type = "list_item", text = "Added a display bar above Mothkeeper Wew’tam to show your collection progress.", level = 2 },
            { type = "h2", text = "PREY" },
            { type = "list_item", text = "Added Big Prey Hunter (Season 1) Feat of Strength for completing the Prey Journey in Season 1.", level = 0 },
            { type = "h2", text = "USER INTERFACE AND ACCESSIBILITY" },
            { type = "list_item", text = "Boss Timeline in the vertical orientation now has an option to set text to be on the left or right.", level = 0 },
            { type = "list_item", text = "Adjusted colors for “gaining threat” and “high threat” on raid frames and nameplates.", level = 0 },
            { type = "list_item", text = "Added a new option to enable or disable spell alert glows for special procs when having the Single Button Assistant on an action bar.", level = 0 },
            { type = "list_item", text = "The Great Vault raid tooltip now displays credit for multiple raids in a better format.", level = 0 },
            { type = "list_item", text = "DAMAGE METERS", level = 0 },
            { type = "list_item", text = "Added an “In Group” visibility option.", level = 1 },
            { type = "list_item", text = "Lowered the minimum window size, allowing you to make the Damage Meters window smaller than before.", level = 1 },
            { type = "list_item", text = "Shift clicking a Damage Meter row now opens a details window that stays open until manually closed.", level = 1 },
            { type = "list_item", text = "During PvP activities, Damage Meter bars are now a different color for allies versus enemies. If the “Show Class Colors” option is enabled, a faction icon is shown instead.", level = 1 },
            { type = "list_item", text = "The Personal Resource Display is now much more customizable:", level = 0 },
            { type = "list_item", text = "New options include controlling overall size, bar width, health bar height, power bar height, padding between bars, opacity, and visibility (Always, In Combat, Hidden).", level = 1 },
            { type = "list_item", text = "The health bar and power bar can now be hidden separately, instead of the previous single option that hid both at once.", level = 1 },
            { type = "list_item", text = "Added options to hide the class resource bar (Combo Points, Soul Shards) on the Personal Resource Display and Player Unit Frame.", level = 1 },
            { type = "list_item", text = "Added a new “Show Class Color” checkbox, which changes the health bar to the player’s class color instead of the default green.", level = 1 },
            { type = "list_item", text = "Added a new “Show Bar Text” checkbox, which enables numbers on the health bar, power bar, and alternate power bar.", level = 1 },
            { type = "list_item", text = "The Personal Resource Display has been updated with new art.", level = 1 },
            { type = "list_item", text = "A few Personal Resource Display bugs have been fixed for Augmentation Evokers.", level = 1 },
            },
        },
        ["2026-05-19-midnight-revelations-1207-ptr-development-notes-420dd8a4f2"] = {
