        ["2026-05-14-bcc-anniversary-edition-overlords-of-outland-now-live-717be282c4"] = {
            id = "2026-05-14-bcc-anniversary-edition-overlords-of-outland-now-live-717be282c4",
            post_key = "717be282c4",
            title = "BCC Anniversary Edition: Overlords of Outland Now Live",
            category = "Blogs (US)",
            timestamp = 1778796679,
            url = "https://news.blizzard.com/en-us/article/24276751/bcc-anniversary-edition-overlords-of-outland-now-live",
            content = {
            { type = "p", text = "Lady Vashj and Kael'thas Sunstrider, the cunning Overlords of Outland, have long served Illidan Stormrage, the Betrayer. As the battle for Outland heats up, it's time to bring their wretched rule to an end. Take the fight to Illidan Stormrage's lieutenants, brave two new raids, compete in Arena Season 2, and pursue new rewards across the shattered world of Outland." },
            { type = "hr" },
            { type = "h2", text = "WHAT'S NEW AT A GLANCE" },
            { type = "list_item", text = "New raids", level = 0 },
            { type = "list_item", text = "​ Tempest Keep: The Eye (Kael'thas Sunstrider) and Serpentshrine Cavern (Lady Vashj)", level = 1 },
            { type = "list_item", text = "Arena Season 2", level = 0 },
            { type = "list_item", text = "​ New rewards and updated progression.", level = 1 },
            { type = "list_item", text = "Swift Flight Form", level = 0 },
            { type = "list_item", text = "​ Druid questline (including the Idol of the Raven Goddess) culminating in a showdown with Anzu the Raven God in Heroic Sethekk Halls", level = 1 },
            { type = "list_item", text = "New daily factions", level = 0 },
            { type = "list_item", text = "​ Earn rewards with Ogri'la and the Sha'tari Skyguard", level = 1 },
            { type = "list_item", text = "New profession recipes", level = 0 },
            { type = "list_item", text = "​ Engineering epic goggles and new Alchemy discoveries (including raid-friendly cauldrons)", level = 1 },
            { type = "hr" },
            { type = "h2", text = "TWO NEW RAIDS" },
            { type = "p", text = "Deep within the halls of Tempest Keep, and the watery depths of Serpentshrine Cavern, Kael'thas Sunstrider and Lady Vashj await any who challenge Illidan's power." },
            { type = "p", text = "It falls to you to put an end to their plans and weaken Illidan's grip on Outland. Gaining access to Serpentshrine Cavern and The Eye in Tempest Keep requires preparation and a trusty band of heroes at your side. Muster your forces and get ready for battle." },
            { type = "h3", text = "The Eye: Vanquish the Sun King" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-05-14-bcc-anniversary-edition-overlords-of-outland-now-live-717be282c4\\image-1.jpg" },
            { type = "p", text = "Infiltrate the heart of a crystalline fortress to end the madness of Kael'thas Sunstrider and his warped loyalists." },
            { type = "list_item", text = "Raid Bosses : 4", level = 0 },
            { type = "list_item", text = "Level : 70", level = 0 },
            { type = "list_item", text = "Location : Tempest Keep, Netherstorm", level = 0 },
            { type = "p", text = "Located within Tempest Keep in the eastern part of Netherstorm, this crystalline fortress is ruled by Kael'thas Sunstrider." },
            { type = "p", text = "Face off against Void Reaver, Al'ar, High Astromancer Solarian, and eventually the Sun King himself, Kael'thas Sunstrider." },
            { type = "p", text = "Three Tier 5 tokens each drop from Void Reaver and Kael'thas Sunstrider." },
            { type = "h3", text = "Serpentshrine Cavern: Confront the Sea Witch" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-05-14-bcc-anniversary-edition-overlords-of-outland-now-live-717be282c4\\image-2.jpg" },
            { type = "p", text = "Slay the twisted Lady Vashj and her vicious fiends in her watery lair." },
            { type = "list_item", text = "Raid Bosses : 6", level = 0 },
            { type = "list_item", text = "Level : 70", level = 0 },
            { type = "list_item", text = "Location : Coilfang Reservoir, Zangarmarsh", level = 0 },
            { type = "p", text = "Found in the depths of Coilfang Reservoir in Zangarmarsh, it is here that Lady Vashj has constructed her watery lair." },
            { type = "p", text = "Face off against five bosses—Hydross the Unstable, The Lurker Below, Leotheras the Blind, Fathom-Lord Karathress, and Morogrim Tidewalker—before confronting Lady Vashj herself." },
            { type = "p", text = "Three Tier 5 tokens each drop from Leotheras the Blind, Fathom-Lord Karathress, and Lady Vashj." },
            { type = "hr" },
            { type = "h2", text = "ARENA SEASON 2" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-05-14-bcc-anniversary-edition-overlords-of-outland-now-live-717be282c4\\image-3.jpg" },
            { type = "p", text = "Brutalize your faction's enemies on the battlefield with the advent of Arena Season 2!" },
            { type = "list_item", text = "When Season 1 ends, there will be a two-week off-season.", level = 0 },
            { type = "list_item", text = "Honor will not be reset at the beginning of Season 2.", level = 0 },
            { type = "list_item", text = "When Season 2 begins, remaining unspent Arena Points are converted to Honor Points at a rate of: 1 Arena Point = 10 Honor Points.", level = 0 },
            { type = "p", text = "Victorious players will earn Arena Points to exchange for powerful gear, climb the ranks against similarly skilled opponents, and compete for an exclusive Gladiator mount awarded to the top 0.5% of players." },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-05-14-bcc-anniversary-edition-overlords-of-outland-now-live-717be282c4\\image-4.jpg" },
            { type = "hr" },
            { type = "h2", text = "DRUID: SWIFT FLIGHT FORM" },
            { type = "p", text = "Druids, your destiny lies in Heroic Sethekk Halls." },
            { type = "p", text = "In Phase 2 of Burning Crusade Classic Anniversary Edition, the questline that rewards Swift Flight Form and the Idol of the Raven Goddess becomes available. Seek out Loganaar in Moonglade to begin once you meet the prerequisites. From there, meet with Morthis Whisperwing, a former member of the Druids of the Talon, at Cenarion Refuge in Zangarmarsh. The final chapter pits you against Anzu the Raven God in Heroic Sethekk Halls, who has a chance to drop the Reins of the Raven Lord." },
            { type = "list_item", text = "Level Requirement : 70", level = 0 },
            { type = "list_item", text = "Riding Skill : Artisan Riding (300 skill, 280% flying speed)", level = 0 },
            { type = "list_item", text = "Reputation : At least Honored with the Lower City faction to access Heroic Sethekk Halls", level = 0 },
            { type = "list_item", text = "Materials : 10 Bogblossoms, 10 Ancient Lichen, 10 Dreaming Glory for early quest stages", level = 0 },
            { type = "p", text = "Only druids who are currently on, or have completed, the questline can summon Anzu." },
            { type = "hr" },
            { type = "h2", text = "TWO NEW FACTIONS FOR DAILY QUESTS AND REWARDS" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-05-14-bcc-anniversary-edition-overlords-of-outland-now-live-717be282c4\\image-5.jpg" },
            { type = "p", text = "Make new allies in Outland with the Ogri'la and Sha'tari Skyguard factions. Complete daily quests to earn these factions' favor and, in turn, receive lucrative rewards." },
            { type = "h3", text = "Ogri'la" },
            { type = "p", text = "A faction of ogres in the Blade's Edge Mountains, where their proximity to Apexis Crystals has allowed them to evolve beyond their brutish nature. They are currently fighting a war against both the Black Dragonflight and the Burning Legion, who seek the Apexis Crystals for their own purposes." },
            { type = "h3", text = "Sha'tari Skyguard" },
            { type = "p", text = "The Sha'tari Skyguard is an air wing of the Sha'tar of Shattrath City, defending the capital from attackers in the hills as well as battling against the arakkoa of Terokk in the peaks of Skettis." },
            { type = "hr" },
            { type = "h2", text = "NEW PROFESSION RECIPES" },
            { type = "p", text = "A variety of powerful new epic goggles can now be crafted with Engineering." },
            { type = "p", text = "Characters with Alchemy can now discover recipes for cauldrons, special items that can provide protection potions for your entire raid when used." },
            { type = "hr" },
            { type = "p", text = "The overlords of Outland await you, champions. Ready your weapons and rally your allies as you continue to defend Azeroth from destruction." },
            },
        },
        ["2026-05-14-ptr-raid-testing-heroic-sporefall-10-30-4dac69dd38"] = {
            id = "2026-05-14-ptr-raid-testing-heroic-sporefall-10-30-4dac69dd38",
            post_key = "4dac69dd38",
            title = "PTR Raid Testing: Heroic Sporefall (10-30)",
            category = "Midnight: Revelations Public Test Realm (US)",
            timestamp = 1778795661,
            url = "https://us.forums.blizzard.com/en/wow/t/2306300/1",
            content = {
            { type = "p", text = "Hello everyone," },
            { type = "p", text = "We will be running a 1-hour test of Sporefall on the public test realm from 1-2pm Pacific Daylight Time (GMT-7) on Thursday, May 21st. During that time players will be able to enter the instance on Heroic difficulty and enjoy the entire raid experience." },
            { type = "p", text = "We hope to see you there." },
            },
        },
        ["2026-05-14-feedback-mythic-sporefall-15-25-75126f0de8"] = {
            id = "2026-05-14-feedback-mythic-sporefall-15-25-75126f0de8",
            post_key = "75126f0de8",
            title = "Feedback: Mythic Sporefall (15-25)",
            category = "Midnight: Revelations Public Test Realm (US)",
            timestamp = 1778787442,
            url = "https://us.forums.blizzard.com/en/wow/t/2306264/1",
            content = {
            { type = "p", text = "Hello," },
            { type = "p", text = "Please share any feedback you have about your experience in Mythic Sporefall in this thread." },
            { type = "p", text = "Noting the nature of your group (pre-made vs. guild), the size of your raid (15-25), and the class/spec you played can also provide great context for your feedback." },
            { type = "p", text = "Thank you for spending your time to test on the PTR - we really appreciate it!" },
            },
        },
