            { type = "list_item", text = "Thrash bleed damage increased by 100%.", level = 2 },
            { type = "list_item", text = "Restoration", level = 1 },
            { type = "list_item", text = "All healing reduced by 3%. Does not apply to PvP combat.", level = 2 },
            { type = "list_item", text = "Everbloom heals for 20/40% of Lifebloom’s final heal (was 25/50%). Does not apply to PvP combat.", level = 2 },
            { type = "list_item", text = "Call of the Elder Druid's cooldown is now trackable in the cooldown manager.", level = 2 },
            { type = "list_item", text = "Evoker", level = 0 },
            { type = "list_item", text = "Augmentation", level = 1 },
            { type = "list_item", text = "All ability damage and pet damage reduced by 5%.", level = 2 },
            { type = "list_item", text = "Fixed an issue where Inferno’s Blessing damage was not properly modified by the specialization baseline passive. Inferno’s Blessing’s spell damage coefficient has been adjusted to compensate, so its effective damage will only be changed per the above adjustment.", level = 2 },
            { type = "list_item", text = "Scalecommander: Fixed an issue where Bombardment damage was not properly modified by the specialization’s baseline passives. Bombardment’s damage calculations have been adjusted to compensate.", level = 2 },
            { type = "dev_note", text = "Effective damage will be unchanged for Devastation and only reduced by 5% for Augmentation with the above adjustment.", level = 3 },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Pack Leader: Corrected an issue where Howl of the Pack Leader would not summon a Boar or a Bear if the Kill Command that would summon the Boar or Bear killed your target.", level = 1 },
            { type = "list_item", text = "Pack Leader: Corrected an issue where the Pack Leader Boar's charge would not grant any of the Hogstrider damage bonuses or deal area damage if your Boar's primary target died before the Boar reached it.", level = 1 },
            { type = "list_item", text = "Beast Mastery", level = 1 },
            { type = "list_item", text = "All damage dealt by you and your pets increased by 4%. Does not apply to PvP combat.", level = 2 },
            { type = "list_item", text = "Corrected an issue where the Piercing Fangs talent did not apply a critical damage bonus to the bonus pet summoned from Nature's Ally.", level = 2 },
            { type = "list_item", text = "Marksmanship", level = 1 },
            { type = "list_item", text = "Rapid Fire damage increased by 20%. Does not affect PvP combat.", level = 2 },
            { type = "list_item", text = "Explosive Shot damage increased by 100%.", level = 2 },
            { type = "list_item", text = "Arcane Shot and Multi-Shot damage increased by 30%.", level = 2 },
            { type = "list_item", text = "Steady Shot damage increased by 100%.", level = 2 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Frost", level = 1 },
            { type = "list_item", text = "Shatter damage to the primary target reduced by 6%.", level = 2 },
            { type = "dev_note", text = "Bug fixes last week to Hand of Frost and Flurry provided a meaningful damage increase to Frost. This change is primarily intended to offset the boost from those fixes.", level = 3 },
            { type = "list_item", text = "Monk", level = 0 },
            { type = "list_item", text = "Brewmaster", level = 1 },
            { type = "list_item", text = "High Tolerance refunds 2/4 seconds of Purifying Brew’s cooldown when cast at Elevated Stagger (was 3/6 seconds).", level = 2 },
            { type = "list_item", text = "Zen State increases stagger effectiveness by 15%, based on missing health (was 20%).", level = 2 },
            { type = "list_item", text = "Fixed an issue where the Season 1 class set 4-piece Extra Kick could target unintended creatures.", level = 2 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Holy", level = 1 },
            { type = "list_item", text = "Eternal Flame healing increased by 15%.", level = 2 },
            { type = "list_item", text = "Word of Glory healing increased by 15%.", level = 2 },
            { type = "list_item", text = "Light of Dawn healing increased by 15%.", level = 2 },
            { type = "list_item", text = "Protection", level = 1 },
            { type = "list_item", text = "Base armor increased by 10%.", level = 2 },
            { type = "list_item", text = "Priest", level = 0 },
            { type = "list_item", text = "Discipline", level = 1 },
            { type = "dev_note", text = "Our goal here is to slightly rein in Atonement’s healing contribution in raid environments while keeping its effectiveness in smaller group content.", level = 2 },
            { type = "list_item", text = "Atonement damage transfer has been increased to 30% (was 28%). Not applied to PvP combat.", level = 2 },
            { type = "list_item", text = "Atonement healing now decays more rapidly beyond 5 targets.", level = 2 },
            { type = "dev_note", text = "For example, when healing 20 injured allies with Atonement, it would previously be reduced by 50%. With the new scaling, it will be reduced by 60%.", level = 3 },
            { type = "list_item", text = "Holy", level = 1 },
            { type = "list_item", text = "All healing increased by 6%. Not applied to PvP combat.", level = 2 },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "list_item", text = "Outlaw", level = 1 },
            { type = "list_item", text = "All damage increased by 9%. Does not affect PvP combat.", level = 2 },
            { type = "list_item", text = "Trickster: Cloud Cover primary and secondary duration reduced to 6 seconds (was 10 seconds).", level = 2 },
            { type = "list_item", text = "Trickster: Cloud Cover now causes Fazed to stack 1 additional time (was 2).", level = 2 },
            { type = "list_item", text = "Trickster: No Scruples crit chance bonus increased to 12% (was 10%).", level = 2 },
            { type = "list_item", text = "Trickster: Additional stacks of Fazed granted by Cloud Cover no longer increase the magnitude of secondary effects, such as the damage reduction from the Smoke talent.", level = 2 },
            { type = "list_item", text = "Subtlety", level = 1 },
            { type = "list_item", text = "All damage increased by 7%. Does not affect PvP combat.", level = 2 },
            { type = "list_item", text = "Trickster: Cloud Cover primary and secondary duration reduced to 6 seconds (was 10 seconds).", level = 2 },
            { type = "list_item", text = "Trickster: No Scruples crit chance bonus increased to 12% (was 10%).", level = 2 },
            { type = "list_item", text = "Trickster: Additional stacks of Fazed granted by Cloud Cover no longer increase the magnitude of secondary effects, such as the damage reduction from the Smoke talent.", level = 2 },
            { type = "list_item", text = "Shaman", level = 0 },
            { type = "list_item", text = "Enhancement", level = 1 },
            { type = "dev_note", text = "Enhancement Shaman has been underperforming in both Raid and M+ content. With these changes, we’re aiming to increase throughput and help Stormbringer catch up to Totemic. We’re also resolving a bug, which would have a negative impact on performance, so we’re watching the results carefully.", level = 2 },
            { type = "list_item", text = "All ability damage increased by 5%.", level = 2 },
            { type = "list_item", text = "Auto attack damage increased by 10%.", level = 2 },
            { type = "list_item", text = "Resolved an issue causing Thorim’s Invocation to cast Lightning Bolt, Chain Lightning and Tempest at with more effectiveness than intended when cast below 10 Maelstrom Weapon.", level = 2 },
            { type = "list_item", text = "Stormbringer: Natural Gift now increases Nature damage of abilities by 6% (was 2%).", level = 2 },
            { type = "list_item", text = "Stormbringer: Voltaic Surge now increases the damage of Crash Lightning and Chain Lightning by 20% (was 10%).", level = 2 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Affliction", level = 1 },
            { type = "list_item", text = "Unstable Affliction damage increased by 20%.", level = 2 },
            { type = "list_item", text = "Seed of Corruption damage increased by 10%.", level = 2 },
            { type = "list_item", text = "Corruption damage increased by 20%.", level = 2 },
            { type = "dev_note", text = "This change does not affect Wither.", level = 3 },
            { type = "list_item", text = "Agony damage increased by 10%.", level = 2 },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "dev_note", text = "These tuning changes are aimed at improving Warrior performance overall as well as compensating for damage lost due to the Deep Wounds bug fix last week. We will continue to monitor Warrior performance and make further adjustments as needed.", level = 1 },
            { type = "list_item", text = "Arms", level = 1 },
            { type = "list_item", text = "Execute damage increased by 20%.", level = 2 },
            { type = "list_item", text = "Overpower damage increased by 20%.", level = 2 },
            { type = "list_item", text = "Slayer: Slayer’s Strike damage increased by 40%.", level = 2 },
            { type = "list_item", text = "Slayer: Reap the Storm damage increased by 30%.", level = 2 },
            { type = "list_item", text = "Fury", level = 1 },
            { type = "list_item", text = "All damage increased by 5%.", level = 2 },
            { type = "list_item", text = "Execute damage increased by 20%.", level = 2 },
            { type = "list_item", text = "Raging Blow damage increased by 20%.", level = 2 },
            { type = "list_item", text = "Slayer: Slayer’s Strike damage increased by 40%.", level = 2 },
            { type = "list_item", text = "Slayer: Reap the Storm damage increased by 30%.", level = 2 },
            { type = "list_item", text = "Mountain Thane: Ground Current damage increased by 50%.", level = 2 },
            { type = "list_item", text = "Protection", level = 1 },
            { type = "list_item", text = "Execute damage increased by 20%.", level = 2 },
            { type = "list_item", text = "Mountain Thane: Thunder Blast damage increased by 30%.", level = 2 },
            { type = "list_item", text = "Mountain Thane: Ground Current damage increased by 50%.", level = 2 },
            { type = "h3", text = "Decor Duel" },
            { type = "list_item", text = "Fixed a bug with the Enchanted Hourglass where the timer would get stuck at 1 second.", level = 0 },
            { type = "list_item", text = "The Enchanted Hourglass can now only be interacted with by the hourglass's owner.", level = 0 },
            { type = "h3", text = "Dungeons and Raids" },
            { type = "list_item", text = "Pit of Saron", level = 0 },
            { type = "list_item", text = "Addressed an issue where Scourgelord Tyrannus could jump out of the playspace and be unable to return.", level = 1 },
            { type = "list_item", text = "Skyreach", level = 0 },
            { type = "list_item", text = "Addressed an issue where Richocheting Chakram can damage pets.", level = 1 },
            { type = "list_item", text = "Amirdrassil, the Dream's Hope", level = 0 },
            { type = "list_item", text = "Addressed an issue that could block progression after defeating Larodar.", level = 1 },
            { type = "list_item", text = "The Voidspire", level = 0 },
            { type = "list_item", text = "Crown of the Cosmos", level = 1 },
            { type = "list_item", text = "Alleria health reduced by 5% in Mythic difficulty.", level = 2 },
            { type = "list_item", text = "Alleria’s berserk timer increased by 15 seconds in Mythic difficulty.", level = 2 },
            { type = "list_item", text = "Demiar, Morium, and Vorelus health in Stage One reduced by 10% in Mythic difficulty.", level = 2 },
            { type = "list_item", text = "Alleria’s energy generation rate in Stage Two reduced by 10% in Mythic difficulty.", level = 2 },
            { type = "list_item", text = "Rift Simulacrum health reduced by 10% in Mythic difficulty.", level = 2 },
            { type = "list_item", text = "Demiar, Morium, and Vorelus energy generation rate in Stage Three reduced by 13% in Mythic difficulty.", level = 2 },
            { type = "list_item", text = "Rift Simulacrum energy generation rate in Stage Two and Three reduced by 13% in Mythic difficulty.", level = 2 },
            { type = "list_item", text = "Spawn time between Rift Simulacrum and Cosmic Portal increased slightly in Mythic difficulty.", level = 2 },
            { type = "list_item", text = "Voidstalker Sting targets 10% fewer players in Stage Three.", level = 2 },
            { type = "list_item", text = "Silverstrike Ricochet width increased to 5 yards (was 4 yards) in Mythic difficulty to match other difficulties.", level = 2 },
            { type = "list_item", text = "March on Quel’Danas", level = 0 },
            { type = "list_item", text = "Belo’ren, Child of Al’ar", level = 1 },
            { type = "list_item", text = "Rebirth is now a 40 second cast on all difficulties (was 30 seconds).", level = 2 },
            { type = "list_item", text = "Reduced the knockback on Light and Void Edict on all difficulties.", level = 2 },
            { type = "list_item", text = "Midnight Falls", level = 1 },
            { type = "list_item", text = "Midnight Crystal health reduced by 5% on Mythic difficulty.", level = 2 },
            { type = "dev_note", text = "The following adjustments are aimed at reducing difficulty for smaller groups, with the greatest reductions applying to 10-player groups. These affect Raid Finder, Normal, and Heroic difficulties.", level = 2 },
            { type = "list_item", text = "Midnight Crystal health reduced by up to 20% in smaller group sizes.", level = 2 },
            { type = "list_item", text = "Cosmic Fracture cast time increased to 14 seconds (was 12 seconds).", level = 2 },
            { type = "list_item", text = "Eclipsed damage reduced by up to 20% in smaller group sizes.", level = 2 },
            { type = "list_item", text = "Starsplinter cast frequency reduced to every 1.3 seconds on Heroic difficulty (was every 1 second).", level = 2 },
            { type = "list_item", text = "Overkill Current damage reduced by 20%.", level = 2 },
            { type = "h3", text = "Enemies and NPCs" },
            { type = "list_item", text = "Rare enemies in Ritual Sites no longer scale incorrectly while in a party.", level = 0 },
            { type = "h3", text = "Items" },
            { type = "list_item", text = "Permafrost Essence now provides 59% less critical strike.", level = 0 },
            { type = "h3", text = "Player versus Player" },
            { type = "dev_note", text = "The pace of PvP combat is a little too fast right now, resulting in quick kills from burst damage. We’re increasing player health in PvP combat to slow this down slightly and give players more time to react.", level = 0 },
            { type = "list_item", text = "Gladiator’s Distinction (PvP trinket set bonus) now increases player Stamina by an additional 5%.", level = 0 },
            { type = "list_item", text = "Voidstone Shielding Array absorption is reduced by 50% in PvP combat.", level = 0 },
            { type = "list_item", text = "Demon Hunter", level = 0 },
            { type = "list_item", text = "Devourer", level = 1 },
            { type = "dev_note", text = "Devourer’s ability to burst enemies down is a little too high.", level = 2 },
            { type = "list_item", text = "Void-Scarred: Voidsurge damage reduced by 20% in PvP combat.", level = 2 },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Balance", level = 1 },
            { type = "dev_note", text = "Overall, Balance Druid is performing reasonably well, with the notable exception of Starsurge feeling underwhelming. We’re increasing Starsurge damage to give Balance more opportunities to contribute single-target burst.", level = 2 },
            { type = "list_item", text = "Starsurge damage increased by 18% in PvP combat.", level = 2 },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Beast Mastery", level = 1 },
            { type = "list_item", text = "All damage dealt by you and your pets reduced by 3% in PvP combat.", level = 2 },
            { type = "list_item", text = "Marksmanship", level = 1 },
            { type = "dev_note", text = "We reduced Marksmanship damage in a recent hotfix, but those changes were too aggressive. We’re pulling back on some of the reductions to Black Arrow and overall damage to bring Marksmanship back up to a reasonable spot.", level = 2 },
            { type = "list_item", text = "Black Arrow damage increased by 11% in PvP combat.", level = 2 },
            { type = "list_item", text = "All damage increased by 5% in PvP combat.", level = 2 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Arcane", level = 1 },
            { type = "dev_note", text = "Arcane is behind the other Mage specializations, so we’re increasing the damage of some of their core spells. These are the more difficult spells to fully channel, so we’d like them to feel more rewarding when you do cast them.", level = 2 },
            { type = "list_item", text = "Arcane Blast damage increased by 15% in PvP combat.", level = 2 },
            { type = "list_item", text = "Arcane Missile damage increased by 15% in PvP combat.", level = 2 },
            { type = "list_item", text = "Fire", level = 1 },
            { type = "dev_note", text = "Fire, particularly Sunfury, is able to deal significant burst during their Combustion windows. We’d like to reduce that with that caveat that casting Fireball should still feel rewarding.", level = 2 },
            { type = "list_item", text = "Pyroblast damage reduced by 6% in PvP combat.", level = 2 },
            { type = "list_item", text = "Fireball damage increased by 80% in PvP combat.", level = 2 },
            { type = "list_item", text = "Sunfury: Codex of the Sunstriders now increases spell damage during Combustion by 1% for each Spellfire Sphere consumed in PvP combat (was 2%).", level = 2 },
            { type = "list_item", text = "Frost", level = 1 },
            { type = "list_item", text = "Ray of Frost damage reduced by 10% in PvP combat.", level = 2 },
            { type = "list_item", text = "Monk", level = 0 },
            { type = "list_item", text = "Brewmaster", level = 1 },
            { type = "list_item", text = "All damage reduced by 15% in PvP combat.", level = 2 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Holy", level = 1 },
            { type = "list_item", text = "Mana regeneration is now reduced by 35% in PvP combat (was 45%).", level = 2 },
            { type = "list_item", text = "Protection", level = 1 },
            { type = "list_item", text = "Templar: Divine Exaction now causes Divine Toll to cast 2 additional times at 75% effectiveness in PvP combat (was 150%).", level = 2 },
            { type = "list_item", text = "Priest", level = 0 },
            { type = "list_item", text = "Shadow", level = 1 },
            { type = "dev_note", text = "Shadow’s consistent damage over time is quite effective, but their single target spells are lower than intended. We’re increasing Shadow Word: Madness and Mind Blast damage to help them contribute single target burst a bit more effectively.", level = 2 },
            { type = "list_item", text = "Shadow Word: Madness damage increased by 25% in PvP combat.", level = 2 },
            { type = "list_item", text = "Mind Blast and Void Blast damage increased by 20% in PvP combat.", level = 2 },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "list_item", text = "Outlaw", level = 1 },
            { type = "dev_note", text = "Outlaw’s damage ended up being quite high after recent adjustments, particularly Between the Eyes with patch 12.0.5. We’re reducing that along with some reductions to Cloud Cover for both PvE and PvP.", level = 2 },
            { type = "list_item", text = "Between the Eyes damage reduced by 15% in PvP combat.", level = 2 },
            { type = "list_item", text = "All ability damage reduced by 5%.", level = 2 },
            { type = "list_item", text = "Shaman", level = 0 },
            { type = "list_item", text = "Restoration", level = 1 },
            { type = "list_item", text = "Healing Wave healing increased by 10% in PvP combat.", level = 2 },
            { type = "list_item", text = "Riptide healing increased by 15% in PvP combat.", level = 2 },
