            { type = "list_item", text = "Death Knight", level = 0 },
            { type = "list_item", text = "Unholy", level = 1 },
            { type = "list_item", text = "Festering Scythe is now an aura on the player, resolving issues that occur when extending the duration of plagues.", level = 2 },
            { type = "dev_note", text = "The underlying issue here was proving to be problematic for a number of reasons and we felt like this would be the safest approach for now.", level = 3 },
            { type = "list_item", text = "Resolved an issue causing Magus of the Dead to not take action immediately on spawn.", level = 2 },
            { type = "list_item", text = "Resolved an issue causing Forbidden Knowledge Rank 4 to activate less than stated.", level = 2 },
            { type = "list_item", text = "Resolved an issue causing Unholy Devotion to grant Haste in addition to attack speed and energy regeneration.", level = 2 },
            { type = "list_item", text = "Disease Cloud is now cast by the Abomination, resolving issues such as it not interacting with pet scaling talents.", level = 2 },
            { type = "list_item", text = "Demon Hunter", level = 0 },
            { type = "list_item", text = "Devourer", level = 1 },
            { type = "list_item", text = "Fixed an issue causing the Single-Button Assistant and Assisted Highlight to not recommend Collapsing Star outside of melee range.", level = 2 },
            { type = "list_item", text = "Vengeance", level = 1 },
            { type = "list_item", text = "Fixed an issue that caused Metamorphosis to be put on cooldown when Last Resort's effect triggered.", level = 2 },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Marksmanship", level = 1 },
            { type = "list_item", text = "Corrected an issue where Unbreakable Bond could give the damage reduction effect to the hunter rather than their pet.", level = 2 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Frost", level = 1 },
            { type = "list_item", text = "Fixed an issue causing Hand of Frost (Rank 2) to not provide the correct percent chance increase per stack of Shatter.", level = 2 },
            { type = "list_item", text = "Paladin", level = 0 },
